# Let me systematically find rectangles and corners for all examples
# A rectangle has horizontal lines of 0s (top, bottom) and vertical lines of 0s (left, right)

def find_rectangles(grid):
    """Find rectangles formed by 0-borders, including partial ones at edges"""
    H, W = len(grid), len(grid[0])
    bg = grid[0][0]

    # Find all 0 cells
    zeros = set()
    for r in range(H):
        for c in range(W):
            if grid[r][c] == 0:
                zeros.add((r,c))

    # Find horizontal segments of 0s
    h_segments = []
    for r in range(H):
        start = None
        for c in range(W+1):
            if c < W and grid[r][c] == 0:
                if start is None:
                    start = c
            else:
                if start is not None:
                    if c - start >= 2:  # at least 2 0s
                        h_segments.append((r, start, c-1))
                    start = None

    # Find vertical segments of 0s
    v_segments = []
    for c in range(W):
        start = None
        for r in range(H+1):
            if r < H and grid[r][c] == 0:
                if start is None:
                    start = r
            else:
                if start is not None:
                    if r - start >= 2:  # at least 2 0s
                        v_segments.append((c, start, r-1))
                    start = None

    print(f"H segments: {h_segments}")
    print(f"V segments: {v_segments}")

for i, s in enumerate(train_samples):
    print(f"\n=== Example {i} ===")
    find_rectangles(np.array(s['input']).tolist())

