# Let me identify candidate markers and their corners
def find_markers_and_corners(grid):
    H, W = len(grid), len(grid[0])
    bg = grid[0][0]

    def dist_to_border(r, c, dr, dc):
        """Distance to nearest 0 in direction (dr,dc)"""
        nr, nc = r+dr, c+dc
        d = 1
        while 0 <= nr < H and 0 <= nc < W:
            if grid[nr][nc] == 0:
                return d
            nr += dr; nc += dc; d += 1
        return None

    markers = []
    for r in range(H):
        for c in range(W):
            v = grid[r][c]
            if v != bg and v != 0:
                du = dist_to_border(r, c, -1, 0)
                dd = dist_to_border(r, c, 1, 0)
                dl = dist_to_border(r, c, 0, -1)
                dr_ = dist_to_border(r, c, 0, 1)

                # Check all 4 corner types
                pairs = []
                if du and dl and du == dl: pairs.append(('TL', du, r-du, c-dl))
                if du and dr_ and du == dr_: pairs.append(('TR', du, r-du, c+dr_))
                if dd and dl and dd == dl: pairs.append(('BL', dd, r+dd, c-dl))
                if dd and dr_ and dd == dr_: pairs.append(('BR', dd, r+dd, c+dr_))

                if pairs:
                    markers.append((r, c, v, pairs))

    return markers

