# Different approach: find rectangles by looking at 0-cell structure
# A rectangle has top, bottom, left, right borders
# Some borders may extend to grid edge (partial rectangles)

def find_rectangles_v2(grid):
    H, W = len(grid), len(grid[0])
    bg = grid[0][0]

    # Find horizontal runs of 0s (length >= 3)
    h_runs = []
    for r in range(H):
        start = None
        for c in range(W+1):
            if c < W and grid[r][c] == 0:
                if start is None: start = c
            else:
                if start is not None and c - start >= 3:
                    h_runs.append((r, start, c-1))
                start = None

    # Find vertical runs of 0s (length >= 3)
    v_runs = []
    for c in range(W):
        start = None
        for r in range(H+1):
            if r < H and grid[r][c] == 0:
                if start is None: start = r
            else:
                if start is not None and r - start >= 3:
                    v_runs.append((c, start, r-1))
                start = None

    # Match h_runs with v_runs to form rectangles
    # A complete rectangle: 2 h_runs (top, bottom) and 2 v_runs (left, right)
    # where top.row = left.start = right.start, bottom.row = left.end = right.end
    # and left.col = top.start = bottom.start, right.col = top.end = bottom.end

    rectangles = []

    # Try all pairs of h_runs
    for i, (r1, c1s, c1e) in enumerate(h_runs):
        for j, (r2, c2s, c2e) in enumerate(h_runs):
            if r2 <= r1: continue
            # Check if there are matching vertical runs
            # Left: col = min of c1s,c2s, rows r1 to r2
            # Right: col = max of c1e,c2e, rows r1 to r2
            # Allow some tolerance for template replacements

            # For now, check exact match
            for vc, vrs, vre in v_runs:
                for vc2, vrs2, vre2 in v_runs:
                    if vc2 <= vc: continue
                    if abs(vrs - r1) <= 1 and abs(vre - r2) <= 1 and abs(vrs2 - r1) <= 1 and abs(vre2 - r2) <= 1:
                        if abs(vc - c1s) <= 1 and abs(vc2 - c1e) <= 1:
                            if abs(vc - c2s) <= 1 and abs(vc2 - c2e) <= 1:
                                rectangles.append((r1, r2, vc, vc2))

    # Also check for partial rectangles (at grid edges)
    # An h_run at the top with a v_run at the left could be a TL corner of a partial rect
    for r, cs, ce in h_runs:
        for vc, vrs, vre in v_runs:
            if abs(vrs - r) <= 1 and abs(vc - cs) <= 1:
                # Potential TL corner
                # Check if right/bottom borders exist or are at grid edge
                has_right = any(abs(vc2 - ce) <= 1 and abs(vrs2 - r) <= 1 for vc2, vrs2, vre2 in v_runs if vc2 > vc)
                has_bottom = any(abs(r2 - vre) <= 1 for r2, c2s, c2e in h_runs if r2 > r)

                if not has_right and ce >= W-2:  # right at grid edge
                    if not has_bottom and vre >= H-2:  # bottom at grid edge
                        rectangles.append((r, H-1, vc, W-1))
                    elif has_bottom:
                        for r2, c2s, c2e in h_runs:
                            if abs(r2 - vre) <= 1 and r2 > r:
                                rectangles.append((r, r2, vc, W-1))
                elif has_right:
                    pass  # already covered by main loop

    return list(set(rectangles)), h_runs, v_runs

for i, s in enumerate(train_samples):
    grid = np.array(s['input']).tolist()
    rects, h_runs, v_runs = find_rectangles_v2(grid)
    print(f"\nExample {i}:")
    print(f"  H runs: {h_runs}")
    print(f"  V runs: {v_runs}")
    print(f"  Rectangles: {rects}")

