def find_structure_components(grid):
    H, W = len(grid), len(grid[0])
    bg = grid[0][0]

    visited = [[False]*W for _ in range(H)]
    components = []

    for r in range(H):
        for c in range(W):
            if grid[r][c] != bg and not visited[r][c]:
                comp = []
                queue = deque([(r,c)])
                visited[r][c] = True
                while queue:
                    cr, cc = queue.popleft()
                    comp.append((cr, cc, grid[cr][cc]))
                    for dr in [-1,0,1]:
                        for dc in [-1,0,1]:
                            if dr==0 and dc==0: continue
                            nr, nc = cr+dr, cc+dc
                            if 0<=nr<H and 0<=nc<W and not visited[nr][nc] and grid[nr][nc] != bg:
                                visited[nr][nc] = True
                                queue.append((nr,nc))
                components.append(comp)
    return components

