# Clean implementation approach
def find_rects_and_markers(grid):
    H, W = len(grid), len(grid[0])
    bg = grid[0][0]

    # Find bounding boxes of 0-cell clusters
    # (Connected components of non-bg cells, then extract 0-cell bbox)
    visited = [[False]*W for _ in range(H)]
    structures = []

    for r in range(H):
        for c in range(W):
            if grid[r][c] != bg and not visited[r][c]:
                comp = []
                queue = deque([(r,c)])
                visited[r][c] = True
                while queue:
                    cr, cc = queue.popleft()
                    comp.append((cr, cc))
                    for dr in [-1,0,1]:
                        for dc in [-1,0,1]:
                            if dr==0 and dc==0: continue
                            nr, nc = cr+dr, cc+dc
                            if 0<=nr<H and 0<=nc<W and not visited[nr][nc] and grid[nr][nc] != bg:
                                visited[nr][nc] = True
                                queue.append((nr,nc))

                zeros = [(r,c) for r,c in comp if grid[r][c] == 0]
                if zeros:
                    # This is a rectangle structure
                    r_min = min(r for r,c in zeros)
                    r_max = max(r for r,c in zeros)
                    c_min = min(c for r,c in zeros)
                    c_max = max(c for r,c in zeros)
                    structures.append({
                        'bbox': (r_min, r_max, c_min, c_max),
                        'cells': comp,
                        'zero_cells': zeros
                    })

    # For each structure, determine which corners are visible
    results = []
    for struct in structures:
        r_min, r_max, c_min, c_max = struct['bbox']
        corners = {}

        # Check each corner
        for ctype, cr, cc, dr_in, dc_in in [
            ('TL', r_min, c_min, 1, 1),
            ('TR', r_min, c_max, 1, -1),
            ('BL', r_max, c_min, -1, 1),
            ('BR', r_max, c_max, -1, -1)
        ]:
            # Check if this corner has 0-border lines emanating from it
            # A corner is "visible" if there are 0s along both border directions from it
            has_h = False  # horizontal border from corner
            has_v = False  # vertical border from corner

            # Check horizontal (move along the row)
            for d in range(1, 4):
                nc = cc + dc_in * d  # move away from corner along top/bottom
                if 0 <= nc < W and grid[cr][nc] == 0:
                    has_h = True
                    break
                # Also check if there's a colored cell at the corner itself

            # Check vertical
            for d in range(1, 4):
                nr = cr + dr_in * d
                if 0 <= nr < H and grid[nr][cc] == 0:
                    has_v = True
                    break

            # Also check if the corner position has a 0 or is at grid edge
            in_grid = 0 <= cr < H and 0 <= cc < W
            if in_grid:
                at_corner = grid[cr][cc] == 0
                at_edge = cr == 0 or cr == H-1 or cc == 0 or cc == W-1
            else:
                at_corner = False
                at_edge = True

            if (has_h or at_edge) and (has_v or at_edge):
                # Find marker: scan inward along diagonal
                marker = None
                for d in range(1, max(H,W)):
                    mr, mc = cr + dr_in * d, cc + dc_in * d
                    if 0 <= mr < H and 0 <= mc < W:
                        v = grid[mr][mc]
                        if v != bg and v != 0:
                            marker = (mr, mc, v, d)
                            break
                    else:
                        break

                if marker:
                    corners[ctype] = {
                        'corner': (cr, cc),
                        'marker': marker[:3],
                        'd': marker[3],
                        'type': ctype
                    }

        results.append({'struct': struct, 'corners': corners})

    return results

for i, s in enumerate(train_samples):
    grid = np.array(s['input']).tolist()
    rects = find_rects_and_markers(grid)
    print(f"\n=== Example {i} ===")
    for j, rect in enumerate(rects):
        print(f"  Rect {j}: bbox={rect['struct']['bbox']}")
        for ctype, info in sorted(rect['corners'].items()):
            print(f"    {ctype}: corner={info['corner']}, marker={info['marker']}, d={info['d']}")

